def check_file_access(user, file_obj):
    if not user.get('is_authenticated'):
        return 'Denied: Unauthenticated'
    if file_obj['is_public']:
        return 'Granted: Public File'
    if user['role'] == 'admin':
        return 'Granted: Admin Clearance'
    if user['clearance'] >= file_obj['required_clearance']:
        return 'Granted: Clearance Verified'
    return 'Denied: Insufficient Clearance'
